code = """import json

# Load papers
papers_path = locals()['var_function-call-4728077729145465214']
with open(papers_path, 'r') as f:
    papers = json.load(f)

# Load citations
citations_path = locals()['var_function-call-11545892236956473361']
with open(citations_path, 'r') as f:
    citations_data = json.load(f)

# Process citations
cit_map = {}
for row in citations_data:
    title = row['title']
    count = int(row['citation_count'])
    year = int(row['citation_year'])
    
    if title not in cit_map:
        cit_map[title] = {'min_year': year, 'total_count': 0}
    
    cit_map[title]['total_count'] += count
    if year < cit_map[title]['min_year']:
        cit_map[title]['min_year'] = year

results = []

for p in papers:
    title = p['filename'].replace('.txt', '')
    text = p.get('text', '').lower()
    
    if 'empirical' in text:
        # Check citation year
        if title in cit_map:
            min_year = cit_map[title]['min_year']
            # Published after 2016 => 2017+.
            # Assuming strictly after: citation > publication => citation >= 2018.
            if min_year >= 2018:
                results.append({
                    'title': title,
                    'total_citations': cit_map[title]['total_count']
                })

print("__RESULT__:")
print(json.dumps(results))"""

